class Solution:
	def insert(self, root, word):
		current = root
		for ch in word:
			if not current.children.has_key(ch):
				current.children[ch] = TrieNode(ch)
			current = current.children[ch]
		current.isEndOfWord = True

	def search(self, root, word):
		current = root
		for ch in word:
			if not current.children.has_key(ch):
				return False
			current = current.children[ch]
		return current.isEndOfWord

	def deleteWithPrefix(self, root, prefix):
		if prefix:
			current = root
			for ch in prefix:
				current = current.children[ch]
			if current.isEndOfWord:
				# Delete all nodes with this prefix
				self._deleteWithPrefix(current, prefix)
				return

	def _deleteWithPrefix(self, current, prefix):
		if not prefix:
			# The end of the prefix, remove it
			current.isEndOfWord = False
			current.value = ''
			return
		ch = prefix[0]
		self._deleteWithPrefix(current.children[ch], prefix[1:])

	def isTrieEmpty(self, root):
		if not root:
			return True
		return not root.isEndOfWord

