class Solution {
public:
	void insert(TrieNode** root, string word) {
		TrieNode* current = *root;
		for (int i = 0; i < word.length(); i++) {
			if (!current->children[word[i] - 'a'])
				current->children[word[i] - 'a'] = new TrieNode(word[i]);
			current = current->children[word[i] - 'a'];
		}
		current->isEndOfWord = true;
	}

	bool search(TrieNode** root, string word) {
		TrieNode* current = *root;
		for (int i = 0; i < word.length(); i++) {
			if (!current->children[word[i] - 'a'])
				return false;
			current = current->children[word[i] - 'a'];
		}
		return current->isEndOfWord;
	}

	void deleteWithPrefix(TrieNode** root, string prefix) {
		if (prefix.empty())
			return;
		TrieNode* current = *root;
		for (int i = 0; i < prefix.length(); i++)
			current = current->children[prefix[i] - 'a'];
		if (current->isEndOfWord)
			self._deleteWithPrefix(current, prefix);
	}

	void _deleteWithPrefix(TrieNode* current, string prefix) {
		if (prefix.empty())
		{
			current->isEndOfWord = false;
			current->value = '';
			return;
		}
		string ch = prefix[0];
		_deleteWithPrefix(current->children[ch], prefix.substr(1));
	}

	bool isTrieEmpty(TrieNode** root) {
		if (!*root)
			return true;
		return !(*root)->isEndOfWord;
	}
};
